def validate_portfolio_dependency_sequencing(
    committed_project_start_weeks: dict[str, int],  # project_id → start_week
    dependencies: list[TeamDependency],
) -> list[str]:
    """
    Return warnings where a successor project starts before its blocking
    predecessor is due to deliver.
    """
    warnings = []
    for dep in dependencies:
        if dep.dependency_type != DependencyType.BLOCKING:
            continue
        # Find which project owns the successor work
        for proj_id, start_week in committed_project_start_weeks.items():
            if start_week < dep.latest_start_week:
                # This project starts before the dependency is satisfied
                warnings.append(
                    f"PROJECT {proj_id} starts W{start_week} but depends on "
                    f"'{dep.predecessor_deliverable}' from {dep.predecessor_team} "
                    f"due W{dep.latest_start_week} — sequencing infeasible."
                )
    return warnings

@dataclass
class DependencyRetroMetrics:
    quarter: str
    total_blocking_deps: int
    resolved_on_time: int
    resolved_late: int
    still_open_at_close: int
    escalated_count: int
    avg_days_late: float

    @property
    def on_time_rate(self) -> float:
        delivered = self.resolved_on_time + self.resolved_late
        return self.resolved_on_time / delivered if delivered else 0.0
